import React from 'react';
import { ErrorMessage, useField, Field, useFormikContext } from 'formik';
import { useTranslation } from 'react-i18next';
import "./KarimField.scss";
import { FaExclamationCircle } from 'react-icons/fa';
import { convert_data_to_select } from '../../Layout/app/Const';
import { SelectField } from '../Ui';

type KarimFieldProps = {
  name: string;
  type: string;
  className?: string;
  option? : any
};

const KarimField: React.FC<KarimFieldProps> = ({ name, type, className = "",option=[], ...props }) => {
  const { t } = useTranslation();
  const [field, meta] = useField({ name, ...props });
  const formik = useFormikContext<any>();

  const isError = meta.touched && meta.error;
  const hasValue = !!field.value; 
  const inputClass = isError ? `${className} is-invalid` : hasValue ? `${className}hasValue` : `${className} `;

  if( type === "checkbox"){
    return (
      <div className="KarimCheckbox">

<label className="cont">
  <input  
  checked={formik.values[name] === 1}
    type="checkbox" 
    name={name}
    onChange={() =>
      formik.setFieldValue(name, formik.values[name] === 1 ? 0 : 1)} />
  <span/>
  {name}
</label>

</div>



    )
  }else if( type === "select"){
      return(
        <> 
         {/* <SelectField label={t(name)} options={convert_data_to_select(option)} name={name}
        onChange={(opt:any) => { formik.setFieldValue(name, opt.value) }} isRequired /> */}
        <h6>{t(item?.name || " ")}</h6>

        <Select
          className="react-select-container"
          classNamePrefix="react-select"
          name={item?.name}
          value={formik.getFieldProps(item?.name).value}
          onChange={options => formik.setFieldValue(item?.name, options)}

          options={convert_data_to_select(item?.option?.filter((e:any) => e[FillterBy] == formik.getFieldProps(FillterTo)?.value))}
          // isMulti={true}
        />
        <ErrorMessage name={item?.name}>
          {(msg:any) => <span className="field-error text-danger">{t(msg)}</span>}
        </ErrorMessage>
      </>


      )

  } 
  else {
    return (
    <div className="KarimField">
      <label htmlFor={field.name} className="text">
      {isError ?  <span className='isErrorIcon'> <FaExclamationCircle/></span> :""}  {name} {""} 
        <ErrorMessage name={field.name}>
        {(msg: any) => <span className="field-error text-danger isErrorIcon">{t(msg)} <FaExclamationCircle/> </span>}
      </ErrorMessage>
      </label>

      <Field
        type={type}
        placeholder="Write Here..."
        name={field.name}
        className={inputClass}
      />


    </div>



  );
  }
};

export default KarimField;
